<module id="multi_pipe_4bit">
    <description>4-bit unsigned number pipeline multiplier with two levels of registers.</description>
    <ports>
        <input id="clk">Clock signal.</input>
        <input id="rst_n">Active-low reset signal.</input>
        <input id="mul_a" width_description="[3:0]">Multiplicand input.</input>
        <input id="mul_b" width_description="[3:0]">Multiplier input.</input>
        <output id="mul_out" width_description="[7:0]">Product output.</output>
    </ports>
    <parameter_description>
        <constant name="size" value="4">Size of the inputs and outputs.</constant>
    </parameter_description>
    <logic_description type="sequential_logic">
        Registers to store intermediate values and control the multiplication process.
    </logic_description>
    <implementation>
        // Extension of input signals
        wire [7:0] a_extended = {4'd0, mul_a};
        wire [7:0] b_extended = {4'd0, mul_b};

        // Partial products generation
        wire [7:0] pp[3:0]; // Partial products array
        genvar i;
        generate
            for (i = 0; i < 4; i = i + 1) begin : gen_partial_products
                assign pp[i] = (mul_b[i]) ? (a_extended << i) : 8'd0;
            end
        endgenerate

        // Intermediate sums storage
        reg [7:0] sum_reg[1:0];

        // Add of partial products
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                sum_reg[0] <= 8'd0;
                sum_reg[1] <= 8'd0;
            end else begin
                sum_reg[0] <= pp[0] + pp[1];
                sum_reg[1] <= sum_reg[0] + pp[2];
            end
        end

        // Final product calculation
        reg [7:0] mul_out_reg;
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                mul_out_reg <= 8'd0;
            end else begin
                mul_out_reg <= sum_reg[1] + pp[3];
            end
        end

        // Output assignment
        assign mul_out = mul_out_reg;
    </implementation>
</module>
```
